import React from "react";

const previewScreens = [
  { label: "Operations Dashboard 1", path: "/stitch-export/operations_dashboard_1/code.html" },
  { label: "Operations Dashboard 2", path: "/stitch-export/operations_dashboard_2/code.html" },
  { label: "Incident Command Center 1", path: "/stitch-export/incident_command_center_1/code.html" },
  { label: "Incident Command Center 2", path: "/stitch-export/incident_command_center_2/code.html" },
  { label: "SLA Escalation Monitoring", path: "/stitch-export/sla_escalation_monitoring/code.html" },
  { label: "IoT Telemetry Monitoring", path: "/stitch-export/iot_telemetry_monitoring_1/code.html" },
  { label: "Route Optimization Planner", path: "/stitch-export/route_optimization_planner/code.html" },
  { label: "Forecasting & Anomalies", path: "/stitch-export/forecasting_anomalies/code.html" },
  { label: "Citizen Complaints Workflow", path: "/stitch-export/citizen_complaints_workflow/code.html" },
  { label: "Supervisor AI Copilot", path: "/stitch-export/supervisor_ai_copilot_1/code.html" }
];

function StitchPreview() {
  return (
    <div className="dashboard-page">
      <div className="page-header">
        <div className="page-header-icon">🎨</div>
        <h1 className="page-title">Stitch UI Preview</h1>
        <p className="page-subtitle">
          Open generated Stitch screens and use them as implementation references.
        </p>
      </div>

      <div className="feature-grid">
        {previewScreens.map((screen) => (
          <div key={screen.path} className="feature-card">
            <h3>{screen.label}</h3>
            <p className="page-subtitle">Generated HTML reference from your Stitch export.</p>
            <a className="btn btn-primary" href={screen.path} target="_blank" rel="noreferrer">
              Open Screen
            </a>
          </div>
        ))}
      </div>
    </div>
  );
}

export default StitchPreview;
